import{BaseComponent as t,html as a,define as e}from"../core.min.js";export class DvProductCard extends t{initialState(){return{id:this.str("id"),name:this.str("name","Product"),price:this.num("price",0)}}add(){this.emit("add-to-cart",{...this.state})}template(){return a`<article class="dv-product-card"><h3>${this.state.name}</h3><p>${this.state.price}</p><button type="button" data-on:click="add">${this.str("action","Add to cart")}</button></article>`}}e("dv-product-card",DvProductCard);
